var COURSE_RU_PL = [{day: 1, title: `Приветствия и первые слова`, title_native: `Powitania i pierwsze słowa`, focus: `Сегодня вы научитесь здороваться, прощаться и вежливо начинать разговор в Варшаве. Эти фразы пригодятся в отеле, кафе и магазине.`, vocab: [{pl: `cześć`, ru: `привет / пока`, ipa: `[чешчь]`},{pl: `dzień dobry`, ru: `добрый день`, ipa: `[джень добры]`},{pl: `dobry wieczór`, ru: `добрый вечер`, ipa: `[добры вечур]`},{pl: `do widzenia`, ru: `до свидания`, ipa: `[до видзэня]`},{pl: `proszę`, ru: `пожалуйста / прошу`, ipa: `[проше]`},{pl: `dziękuję`, ru: `спасибо`, ipa: `[дженкуе]`},{pl: `tak`, ru: `да`, ipa: `[так]`},{pl: `nie`, ru: `нет`, ipa: `[не]`},{pl: `przepraszam`, ru: `извините`, ipa: `[пшепрашам]`}], phrases: [{pl: `Dzień dobry.`, ru: `Добрый день.`, ipa: `[джень добры]`},{pl: `Cześć, jak się masz?`, ru: `Привет, как дела?`, ipa: `[чешчь, як ще маш]`},{pl: `Dziękuję bardzo.`, ru: `Большое спасибо.`, ipa: `[дженкуе бардзо]`},{pl: `Przepraszam, proszę.`, ru: `Извините, пожалуйста.`, ipa: `[пшепрашам, проше]`},{pl: `Do widzenia.`, ru: `До свидания.`, ipa: `[до видзэня]`}], grammar: `В польском языке вежливая форма очень важна, особенно с незнакомыми людьми. В магазине, отеле или ресторане лучше начинать с Dzień dobry, а не с Cześć. Слово proszę может значить и «пожалуйста», и «прошу», и «вот, держите».`, practice: [`Скажите по-польски «Добрый день» незнакомому человеку.`,`Переведите: «Спасибо большое».`,`Представьте, что вы случайно задели человека в трамвае. Что скажете?`,`Составьте короткий диалог: приветствие, спасибо, прощание.`,`Повторите вслух слова tak, nie, proszę, dziękuję.`]},{day: 2, title: `Представление себя`, title_native: `Przedstawianie się`, focus: `Сегодня вы научитесь говорить, как вас зовут и откуда вы. Сцена — хостел в Кракове, где вы знакомитесь с другими путешественниками.`, vocab: [{pl: `imię`, ru: `имя`, ipa: `[имье]`},{pl: `nazywam się`, ru: `меня зовут`, ipa: `[называм ще]`},{pl: `jestem`, ru: `я есть / я`, ipa: `[естэм]`},{pl: `z`, ru: `из`, ipa: `[з]`},{pl: `Rosja`, ru: `Россия`, ipa: `[росья]`},{pl: `Polska`, ru: `Польша`, ipa: `[польска]`},{pl: `miło`, ru: `приятно`, ipa: `[мило]`},{pl: `poznać`, ru: `познакомиться`, ipa: `[познаць]`},{pl: `turysta`, ru: `турист`, ipa: `[турыста]`},{pl: `turystka`, ru: `туристка`, ipa: `[турыстка]`}], phrases: [{pl: `Nazywam się Anna.`, ru: `Меня зовут Анна.`, ipa: `[называм ще анна]`},{pl: `Jestem z Rosji.`, ru: `Я из России.`, ipa: `[естэм з росъи]`},{pl: `Miło mi.`, ru: `Мне приятно.`, ipa: `[мило ми]`},{pl: `Miło cię poznać.`, ru: `Приятно познакомиться.`, ipa: `[мило че познаць]`},{pl: `Jestem turystą.`, ru: `Я турист.`, ipa: `[естэм турыстом]`},{pl: `Jestem turystką.`, ru: `Я туристка.`, ipa: `[естэм турыстком]`}], grammar: `Фраза nazywam się буквально значит «я называюсь». Для мужчин: jestem turystą, для женщин: jestem turystką. В польском часто меняется окончание слова в зависимости от пола говорящего.`, practice: [`Скажите по-польски: «Меня зовут…».`,`Скажите: «Я из России».`,`Выберите правильную форму: jestem turystą или jestem turystką.`,`Ответьте на вопрос: Jak się nazywasz?`,`Составьте мини-диалог знакомства из 4 реплик.`]},{day: 3, title: `Вежливые просьбы`, title_native: `Uprzejme prośby`, focus: `Сегодня вы научитесь просить о помощи в Познани. Это особенно полезно, когда вы не знаете слово или не понимаете ответ.`, vocab: [{pl: `pomoc`, ru: `помощь`, ipa: `[помоц]`},{pl: `proszę`, ru: `пожалуйста`, ipa: `[проше]`},{pl: `można`, ru: `можно`, ipa: `[можна]`},{pl: `czy`, ru: `ли / вопросительная частица`, ipa: `[чы]`},{pl: `powoli`, ru: `медленно`, ipa: `[поволи]`},{pl: `jeszcze raz`, ru: `ещё раз`, ipa: `[ещче раз]`},{pl: `rozumiem`, ru: `понимаю`, ipa: `[розумем]`},{pl: `nie rozumiem`, ru: `не понимаю`, ipa: `[не розумем]`},{pl: `mówić`, ru: `говорить`, ipa: `[мувичь]`},{pl: `po polsku`, ru: `по-польски`, ipa: `[по польску]`}], phrases: [{pl: `Czy można prosić o pomoc?`, ru: `Можно попросить о помощи?`, ipa: `[чы можна просичь о помоц]`},{pl: `Proszę mówić powoli.`, ru: `Говорите, пожалуйста, медленно.`, ipa: `[проше мувичь поволи]`},{pl: `Proszę jeszcze raz.`, ru: `Пожалуйста, ещё раз.`, ipa: `[проше ещче раз]`},{pl: `Nie rozumiem.`, ru: `Я не понимаю.`, ipa: `[не розумем]`},{pl: `Czy mówi pan po rosyjsku?`, ru: `Вы говорите по-русски?`, ipa: `[чы муви пан по росыйску]`},{pl: `Czy mówi pani po angielsku?`, ru: `Вы говорите по-английски?`, ipa: `[чы муви пани по ангельску]`}], grammar: `В польском вежливые обращения pan и pani похожи на «господин» и «госпожа», но используются намного чаще. Czy ставится в начале вопроса, чтобы сделать его ясным. Можно сказать Czy można...? — это очень удобная вежливая конструкция.`, practice: [`Попросите человека говорить медленно.`,`Скажите: «Я не понимаю».`,`Спросите вежливо у мужчины, говорит ли он по-английски.`,`Спросите у женщины, говорит ли она по-русски.`,`Переведите: «Можно попросить о помощи?»`]},{day: 4, title: `Числа от 0 до 20`, title_native: `Liczby od 0 do 20`, focus: `Сегодня вы выучите базовые числа для цен, адресов и билетов. Представьте, что вы покупаете воду и билет в киоске в Гданьске.`, vocab: [{pl: `zero`, ru: `ноль`, ipa: `[зэро]`},{pl: `jeden`, ru: `один`, ipa: `[еден]`},{pl: `dwa`, ru: `два`, ipa: `[два]`},{pl: `trzy`, ru: `три`, ipa: `[тшы]`},{pl: `cztery`, ru: `четыре`, ipa: `[чтэры]`},{pl: `pięć`, ru: `пять`, ipa: `[пеньчь]`},{pl: `sześć`, ru: `шесть`, ipa: `[шешчь]`},{pl: `siedem`, ru: `семь`, ipa: `[щедэм]`},{pl: `osiem`, ru: `восемь`, ipa: `[ощем]`},{pl: `dziesięć`, ru: `десять`, ipa: `[джешеньчь]`}], phrases: [{pl: `Mam jeden bilet.`, ru: `У меня один билет.`, ipa: `[мам еден билет]`},{pl: `Poproszę dwa bilety.`, ru: `Два билета, пожалуйста.`, ipa: `[попроше два билеты]`},{pl: `To kosztuje pięć złotych.`, ru: `Это стоит пять злотых.`, ipa: `[то коштуе пеньчь злотых]`},{pl: `Mam dziesięć złotych.`, ru: `У меня десять злотых.`, ipa: `[мам джешеньчь злотых]`},{pl: `Numer cztery.`, ru: `Номер четыре.`, ipa: `[нумэр чтэры]`}], grammar: `После чисел формы существительных могут меняться: jeden bilet, dwa bilety, pięć biletów. Для путешественника сначала важнее понимать сами числа и цену. Слово złoty меняется: jeden złoty, dwa złote, pięć złotych.`, practice: [`Посчитайте вслух от 0 до 10.`,`Скажите: «Два билета, пожалуйста».`,`Переведите: «Это стоит пять злотых».`,`Назовите номер вашей комнаты по-польски.`,`Составьте фразу с числом trzy.`]},{day: 5, title: `Числа, цены и время`, title_native: `Liczby, ceny i czas`, focus: `Сегодня вы продолжите числа до 100 и потренируете цены. Сцена — рынок во Вроцлаве, где вы покупаете фрукты и сувениры.`, vocab: [{pl: `jedenaście`, ru: `одиннадцать`, ipa: `[едэнашче]`},{pl: `dwanaście`, ru: `двенадцать`, ipa: `[дванашче]`},{pl: `dwadzieścia`, ru: `двадцать`, ipa: `[дваджещча]`},{pl: `trzydzieści`, ru: `тридцать`, ipa: `[тшыджешчи]`},{pl: `czterdzieści`, ru: `сорок`, ipa: `[чтэрджешчи]`},{pl: `pięćdziesiąt`, ru: `пятьдесят`, ipa: `[пеньджешёнт]`},{pl: `sto`, ru: `сто`, ipa: `[сто]`},{pl: `złoty`, ru: `злотый`, ipa: `[злоты]`},{pl: `grosz`, ru: `грош`, ipa: `[грош]`},{pl: `cena`, ru: `цена`, ipa: `[цэна]`}], phrases: [{pl: `Ile to kosztuje?`, ru: `Сколько это стоит?`, ipa: `[иле то коштуе]`},{pl: `To kosztuje dwadzieścia złotych.`, ru: `Это стоит двадцать злотых.`, ipa: `[то коштуе дваджещча злотых]`},{pl: `Czy mogę zapłacić kartą?`, ru: `Можно заплатить картой?`, ipa: `[чы моге заплачичь картом]`},{pl: `Mam tylko gotówkę.`, ru: `У меня только наличные.`, ipa: `[мам тылько готувке]`},{pl: `Za drogo.`, ru: `Слишком дорого.`, ipa: `[за дрого]`},{pl: `Poproszę rachunek.`, ru: `Счёт, пожалуйста.`, ipa: `[попроше рахунэк]`}], grammar: `Вопрос Ile to kosztuje? универсален и подходит почти везде. Kartą значит «картой», gotówką — «наличными». В Польше часто можно платить картой даже за маленькие покупки, но на рынках наличные всё ещё полезны.`, practice: [`Спросите цену сувенира.`,`Скажите: «Можно заплатить картой?»`,`Назовите по-польски числа 20, 30, 50, 100.`,`Скажите: «Это слишком дорого».`,`Сыграйте диалог продавца и покупателя на рынке.`]},{day: 6, title: `В кафе`, title_native: `W kawiarni`, focus: `Сегодня вы научитесь заказывать кофе и простую еду в кафе в Кракове. Эти фразы помогут вам звучать вежливо и уверенно.`, vocab: [{pl: `kawa`, ru: `кофе`, ipa: `[кава]`},{pl: `herbata`, ru: `чай`, ipa: `[хэрбата]`},{pl: `woda`, ru: `вода`, ipa: `[вода]`},{pl: `mleko`, ru: `молоко`, ipa: `[млэко]`},{pl: `cukier`, ru: `сахар`, ipa: `[цукер]`},{pl: `ciasto`, ru: `пирожное / торт`, ipa: `[чясто]`},{pl: `kanapka`, ru: `бутерброд`, ipa: `[канапка]`},{pl: `mały`, ru: `маленький`, ipa: `[малы]`},{pl: `duży`, ru: `большой`, ipa: `[дужы]`},{pl: `stolik`, ru: `столик`, ipa: `[столик]`}], phrases: [{pl: `Poproszę kawę.`, ru: `Кофе, пожалуйста.`, ipa: `[попроше каве]`},{pl: `Poproszę herbatę z cytryną.`, ru: `Чай с лимоном, пожалуйста.`, ipa: `[попроше хэрбате з цытрыном]`},{pl: `Czy jest mleko?`, ru: `Есть молоко?`, ipa: `[чы ест млэко]`},{pl: `Bez cukru, proszę.`, ru: `Без сахара, пожалуйста.`, ipa: `[бэз цукру проше]`},{pl: `Na miejscu czy na wynos?`, ru: `Здесь или с собой?`, ipa: `[на мейсцу чы на вынос]`},{pl: `Na miejscu, proszę.`, ru: `Здесь, пожалуйста.`, ipa: `[на мейсцу проше]`}], grammar: `Poproszę — самая удобная форма заказа: «я попрошу». После неё часто используется винительный падеж: kawę, herbatę, wodę. Фраза na wynos значит «с собой», а na miejscu — «на месте».`, practice: [`Закажите кофе без сахара.`,`Скажите: «Чай с лимоном, пожалуйста».`,`Ответьте на вопрос: Na miejscu czy na wynos?`,`Спросите, есть ли молоко.`,`Составьте заказ из напитка и десерта.`]},{day: 7, title: `Еда и простые предпочтения`, title_native: `Jedzenie i proste preferencje`, focus: `Сегодня вы научитесь говорить, что вам нравится и что вы хотите съесть. Сцена — небольшой бар mleczny в Варшаве.`, vocab: [{pl: `jedzenie`, ru: `еда`, ipa: `[едзэне]`},{pl: `chleb`, ru: `хлеб`, ipa: `[хлэп]`},{pl: `ser`, ru: `сыр`, ipa: `[сэр]`},{pl: `mięso`, ru: `мясо`, ipa: `[меньсо]`},{pl: `ryba`, ru: `рыба`, ipa: `[рыба]`},{pl: `zupa`, ru: `суп`, ipa: `[зупа]`},{pl: `pierogi`, ru: `вареники / пироги`, ipa: `[пьероги]`},{pl: `lubię`, ru: `я люблю / мне нравится`, ipa: `[лубе]`},{pl: `chcę`, ru: `я хочу`, ipa: `[хце]`},{pl: `smaczne`, ru: `вкусное`, ipa: `[смачнэ]`}], phrases: [{pl: `Lubię pierogi.`, ru: `Я люблю пироги.`, ipa: `[лубе пьероги]`},{pl: `Nie jem mięsa.`, ru: `Я не ем мясо.`, ipa: `[не ем меньса]`},{pl: `Chcę coś małego.`, ru: `Я хочу что-нибудь маленькое.`, ipa: `[хце цось малэго]`},{pl: `To jest bardzo smaczne.`, ru: `Это очень вкусно.`, ipa: `[то ест бардзо смачнэ]`},{pl: `Czy to jest z mięsem?`, ru: `Это с мясом?`, ipa: `[чы то ест з меньсэм]`},{pl: `Poproszę zupę.`, ru: `Суп, пожалуйста.`, ipa: `[попроше зупе]`}], grammar: `Глагол lubię требует объект: lubię kawę, lubię pierogi. Если вы не едите мясо, фраза Nie jem mięsa очень полезна. В польской кухне pierogi — одно из самых известных блюд, но они бывают с разными начинками.`, practice: [`Скажите, что вы любите пироги.`,`Спросите, есть ли мясо в блюде.`,`Скажите: «Я не ем мясо».`,`Похвалите блюдо.`,`Закажите суп и воду.`]},{day: 8, title: `Отель и регистрация`, title_native: `Hotel i zameldowanie`, focus: `Сегодня вы научитесь заселяться в отель в Гданьске. Вы сможете назвать бронь, паспорт и попросить ключ.`, vocab: [{pl: `hotel`, ru: `отель`, ipa: `[хотэль]`},{pl: `rezerwacja`, ru: `бронь`, ipa: `[рэзэрвацыя]`},{pl: `pokój`, ru: `комната / номер`, ipa: `[покуй]`},{pl: `klucz`, ru: `ключ`, ipa: `[ключ]`},{pl: `paszport`, ru: `паспорт`, ipa: `[пашпорт]`},{pl: `noc`, ru: `ночь`, ipa: `[ноц]`},{pl: `śniadanie`, ru: `завтрак`, ipa: `[щнядане]`},{pl: `winda`, ru: `лифт`, ipa: `[винда]`},{pl: `piętro`, ru: `этаж`, ipa: `[пьентро]`},{pl: `recepcja`, ru: `ресепшен`, ipa: `[рэцэпцыя]`}], phrases: [{pl: `Mam rezerwację.`, ru: `У меня бронь.`, ipa: `[мам рэзэрвацые]`},{pl: `Na nazwisko Iwanow.`, ru: `На фамилию Иванов.`, ipa: `[на назвиско иванов]`},{pl: `Oto mój paszport.`, ru: `Вот мой паспорт.`, ipa: `[ото муй пашпорт]`},{pl: `Czy śniadanie jest w cenie?`, ru: `Завтрак включён в цену?`, ipa: `[чы щнядане ест в цэне]`},{pl: `Gdzie jest winda?`, ru: `Где лифт?`, ipa: `[гджэ ест винда]`},{pl: `Poproszę klucz do pokoju.`, ru: `Ключ от номера, пожалуйста.`, ipa: `[попроше ключ до покою]`}], grammar: `Слово pokój значит и «комната», и «номер в отеле». Фраза na nazwisko используется при брони: «на фамилию». Вежливый вопрос Czy śniadanie jest w cenie? поможет узнать, включён ли завтрак.`, practice: [`Скажите на ресепшене: «У меня бронь».`,`Назовите бронь на свою фамилию.`,`Спросите, где лифт.`,`Спросите, включён ли завтрак.`,`Попросите ключ от номера.`]},{day: 9, title: `Адреса и направления`, title_native: `Adresy i kierunki`, focus: `Сегодня вы научитесь спрашивать дорогу в центре Варшавы. Вы сможете понять простые указания: прямо, налево, направо.`, vocab: [{pl: `gdzie`, ru: `где`, ipa: `[гджэ]`},{pl: `ulica`, ru: `улица`, ipa: `[улица]`},{pl: `plac`, ru: `площадь`, ipa: `[пляц]`},{pl: `prawo`, ru: `право`, ipa: `[право]`},{pl: `lewo`, ru: `лево`, ipa: `[лево]`},{pl: `prosto`, ru: `прямо`, ipa: `[просто]`},{pl: `blisko`, ru: `близко`, ipa: `[блиско]`},{pl: `daleko`, ru: `далеко`, ipa: `[далэко]`},{pl: `tutaj`, ru: `здесь`, ipa: `[тутай]`},{pl: `tam`, ru: `там`, ipa: `[там]`}], phrases: [{pl: `Gdzie jest ta ulica?`, ru: `Где эта улица?`, ipa: `[гджэ ест та улица]`},{pl: `Proszę iść prosto.`, ru: `Идите прямо, пожалуйста.`, ipa: `[проше ищчь просто]`},{pl: `W lewo.`, ru: `Налево.`, ipa: `[в лево]`},{pl: `W prawo.`, ru: `Направо.`, ipa: `[в право]`},{pl: `Czy to daleko?`, ru: `Это далеко?`, ipa: `[чы то далэко]`},{pl: `To jest blisko.`, ru: `Это близко.`, ipa: `[то ест блиско]`}], grammar: `В указаниях часто используется iść — «идти». Фраза Proszę iść prosto звучит вежливо и естественно. W lewo и w prawo буквально означают «влево» и «вправо».`, practice: [`Спросите, где находится улица.`,`Скажите: «Идите прямо».`,`Переведите: «Это далеко?»`,`Дайте маршрут: прямо, направо, налево.`,`Представьте, что вы ищете центральную площадь.`]},{day: 10, title: `Городской транспорт`, title_native: `Transport miejski`, focus: `Сегодня вы научитесь пользоваться автобусом, трамваем и метро в Варшаве. Вы сможете купить билет и спросить о нужной остановке.`, vocab: [{pl: `bilet`, ru: `билет`, ipa: `[билет]`},{pl: `autobus`, ru: `автобус`, ipa: `[аутобус]`},{pl: `tramwaj`, ru: `трамвай`, ipa: `[трамвай]`},{pl: `metro`, ru: `метро`, ipa: `[мэтро]`},{pl: `przystanek`, ru: `остановка`, ipa: `[пшыстанэк]`},{pl: `stacja`, ru: `станция`, ipa: `[стацыя]`},{pl: `linia`, ru: `линия`, ipa: `[линя]`},{pl: `kierunek`, ru: `направление`, ipa: `[керунэк]`},{pl: `ważny`, ru: `действительный`, ipa: `[важны]`},{pl: `kontrola`, ru: `контроль`, ipa: `[контроля]`}], phrases: [{pl: `Poproszę bilet normalny.`, ru: `Обычный билет, пожалуйста.`, ipa: `[попроше билет нормальны]`},{pl: `Gdzie jest przystanek?`, ru: `Где остановка?`, ipa: `[гджэ ест пшыстанэк]`},{pl: `Czy ten tramwaj jedzie do centrum?`, ru: `Этот трамвай едет в центр?`, ipa: `[чы тэн трамвай едже до цэнтрум]`},{pl: `Która to linia?`, ru: `Какая это линия?`, ipa: `[ктура то линя]`},{pl: `Muszę skasować bilet.`, ru: `Мне нужно прокомпостировать билет.`, ipa: `[муше скасовачь билет]`},{pl: `Jadę do centrum.`, ru: `Я еду в центр.`, ipa: `[яде до цэнтрум]`}], grammar: `В польском транспорт «едет» — jedzie. Фраза jadę do centrum значит «я еду в центр». В городском транспорте билет часто нужно активировать: skasować bilet.`, practice: [`Купите обычный билет.`,`Спросите, где остановка.`,`Спросите, едет ли трамвай в центр.`,`Скажите: «Я еду в центр».`,`Объясните, что вам нужно активировать билет.`]},{day: 11, title: `Поезд и вокзал`, title_native: `Pociąg i dworzec`, focus: `Сегодня вы научитесь покупать билет на поезд и ориентироваться на вокзале в Кракове. Это пригодится для поездок между городами Польши.`, vocab: [{pl: `pociąg`, ru: `поезд`, ipa: `[почёнг]`},{pl: `dworzec`, ru: `вокзал`, ipa: `[двожэц]`},{pl: `peron`, ru: `платформа`, ipa: `[пэрон]`},{pl: `wagon`, ru: `вагон`, ipa: `[вагон]`},{pl: `miejsce`, ru: `место`, ipa: `[мейсцэ]`},{pl: `bilet ulgowy`, ru: `льготный билет`, ipa: `[билет ульговы]`},{pl: `bilet normalny`, ru: `обычный билет`, ipa: `[билет нормальны]`},{pl: `odjazd`, ru: `отправление`, ipa: `[одъязд]`},{pl: `przyjazd`, ru: `прибытие`, ipa: `[пшыязд]`},{pl: `opóźnienie`, ru: `задержка`, ipa: `[опужнене]`}], phrases: [{pl: `Poproszę bilet do Krakowa.`, ru: `Билет до Кракова, пожалуйста.`, ipa: `[попроше билет до кракова]`},{pl: `O której odjeżdża pociąg?`, ru: `Во сколько отправляется поезд?`, ipa: `[о ктурэй одъежджа почёнг]`},{pl: `Z którego peronu?`, ru: `С какой платформы?`, ipa: `[з ктурэго пэрону]`},{pl: `Czy to miejsce jest wolne?`, ru: `Это место свободно?`, ipa: `[чы то мейсцэ ест вольнэ]`},{pl: `Pociąg ma opóźnienie.`, ru: `Поезд задерживается.`, ipa: `[почёнг ма опужнене]`},{pl: `Gdzie jest wagon drugi?`, ru: `Где второй вагон?`, ipa: `[гджэ ест вагон други]`}], grammar: `Do + города часто означает направление: do Krakowa, do Warszawy, do Gdańska. Вопрос o której? значит «во сколько?». На вокзале важно различать peron — платформа и wagon — вагон.`, practice: [`Купите билет до Кракова.`,`Спросите, с какой платформы поезд.`,`Спросите, свободно ли место.`,`Скажите: «Поезд задерживается».`,`Спросите, где второй вагон.`]},{day: 12, title: `Такси и приложения`, title_native: `Taksówka i aplikacje`, focus: `Сегодня вы научитесь говорить с водителем такси или пользоваться поездкой через приложение в Варшаве. Вы сможете назвать адрес и уточнить цену.`, vocab: [{pl: `taksówka`, ru: `такси`, ipa: `[таксувка]`},{pl: `kierowca`, ru: `водитель`, ipa: `[керофца]`},{pl: `adres`, ru: `адрес`, ipa: `[адрэс]`},{pl: `lotnisko`, ru: `аэропорт`, ipa: `[лотниско]`},{pl: `centrum`, ru: `центр`, ipa: `[цэнтрум]`},{pl: `hotel`, ru: `отель`, ipa: `[хотэль]`},{pl: `szybko`, ru: `быстро`, ipa: `[шыбко]`},{pl: `wolno`, ru: `медленно`, ipa: `[вольно]`},{pl: `rachunek`, ru: `счёт`, ipa: `[рахунэк]`},{pl: `gotówka`, ru: `наличные`, ipa: `[готувка]`}], phrases: [{pl: `Proszę jechać na ten adres.`, ru: `Езжайте, пожалуйста, по этому адресу.`, ipa: `[проше ехачь на тэн адрэс]`},{pl: `Ile to będzie kosztować?`, ru: `Сколько это будет стоить?`, ipa: `[иле то бенджэ коштовачь]`},{pl: `Na lotnisko, proszę.`, ru: `В аэропорт, пожалуйста.`, ipa: `[на лотниско проше]`},{pl: `Czy mogę zapłacić kartą?`, ru: `Можно оплатить картой?`, ipa: `[чы моге заплачичь картом]`},{pl: `Proszę tutaj się zatrzymać.`, ru: `Остановитесь здесь, пожалуйста.`, ipa: `[проше тутай ще затшымачь]`},{pl: `Potrzebuję rachunek.`, ru: `Мне нужен счёт.`, ipa: `[потшебуе рахунэк]`}], grammar: `Фраза Proszę jechać... вежливо просит водителя ехать куда-либо. Na lotnisko — «в аэропорт», do hotelu — «в отель». В Польше многие такси и приложения принимают оплату картой.`, practice: [`Попросите ехать в аэропорт.`,`Спросите стоимость поездки.`,`Скажите водителю остановиться здесь.`,`Спросите, можно ли оплатить картой.`,`Попросите счёт.`]},{day: 13, title: `Покупки в магазине`, title_native: `Zakupy w sklepie`, focus: `Сегодня вы научитесь покупать продукты в маленьком магазине в Лодзи. Вы сможете спросить цену, количество и попросить пакет.`, vocab: [{pl: `sklep`, ru: `магазин`, ipa: `[склэп]`},{pl: `chleb`, ru: `хлеб`, ipa: `[хлэп]`},{pl: `woda`, ru: `вода`, ipa: `[вода]`},{pl: `jabłko`, ru: `яблоко`, ipa: `[ябўко]`},{pl: `banan`, ru: `банан`, ipa: `[банан]`},{pl: `ser`, ru: `сыр`, ipa: `[сэр]`},{pl: `torba`, ru: `сумка / пакет`, ipa: `[торба]`},{pl: `paragon`, ru: `чек`, ipa: `[парагон]`},{pl: `kasa`, ru: `касса`, ipa: `[каса]`},{pl: `otwarte`, ru: `открыто`, ipa: `[отвартэ]`}], phrases: [{pl: `Poproszę chleb i wodę.`, ru: `Хлеб и воду, пожалуйста.`, ipa: `[попроше хлэп и воде]`},{pl: `Czy sklep jest otwarty?`, ru: `Магазин открыт?`, ipa: `[чы склэп ест отварты]`},{pl: `Czy mogę dostać torbę?`, ru: `Можно пакет?`, ipa: `[чы моге достачь торбе]`},{pl: `Ile płacę?`, ru: `Сколько я плачу?`, ipa: `[иле плаце]`},{pl: `Poproszę paragon.`, ru: `Чек, пожалуйста.`, ipa: `[попроше парагон]`},{pl: `To wszystko.`, ru: `Это всё.`, ipa: `[то вшыстко]`}], grammar: `Фраза Poproszę... подходит почти для любой покупки. To wszystko означает «это всё» и удобно завершает заказ. Paragon — обычный чек, который часто дают автоматически.`, practice: [`Купите хлеб и воду.`,`Спросите, открыт ли магазин.`,`Попросите пакет.`,`Скажите: «Это всё».`,`Попросите чек.`]},{day: 14, title: `Одежда и размеры`, title_native: `Ubrania i rozmiary`, focus: `Сегодня вы научитесь покупать одежду в торговом центре в Варшаве. Вы сможете спросить размер, примерочную и цену.`, vocab: [{pl: `ubranie`, ru: `одежда`, ipa: `[убране]`},{pl: `koszula`, ru: `рубашка`, ipa: `[кошуля]`},{pl: `spodnie`, ru: `брюки`, ipa: `[сподне]`},{pl: `sukienka`, ru: `платье`, ipa: `[сукенка]`},{pl: `buty`, ru: `обувь`, ipa: `[буты]`},{pl: `rozmiar`, ru: `размер`, ipa: `[розмяр]`},{pl: `mały`, ru: `маленький`, ipa: `[малы]`},{pl: `duży`, ru: `большой`, ipa: `[дужы]`},{pl: `przymierzalnia`, ru: `примерочная`, ipa: `[пшымежальня]`},{pl: `kolor`, ru: `цвет`, ipa: `[колор]`}], phrases: [{pl: `Czy jest większy rozmiar?`, ru: `Есть размер больше?`, ipa: `[чы ест венкшы розмяр]`},{pl: `Czy jest mniejszy rozmiar?`, ru: `Есть размер меньше?`, ipa: `[чы ест мнэйшы розмяр]`},{pl: `Gdzie jest przymierzalnia?`, ru: `Где примерочная?`, ipa: `[гджэ ест пшымежальня]`},{pl: `Ile kosztują te buty?`, ru: `Сколько стоит эта обувь?`, ipa: `[иле коштуйом тэ буты]`},{pl: `Podoba mi się ten kolor.`, ru: `Мне нравится этот цвет.`, ipa: `[подоба ми ще тэн колор]`},{pl: `Tylko oglądam.`, ru: `Я только смотрю.`, ipa: `[тылько оглёндам]`}], grammar: `Podoba mi się значит «мне нравится», но построено иначе, чем в русском. Можно сказать Podoba mi się ten kolor или Podobają mi się te buty. Если продавец подходит, фраза Tylko oglądam звучит естественно и вежливо.`, practice: [`Спросите, где примерочная.`,`Попросите размер больше.`,`Скажите, что вам нравится цвет.`,`Спросите цену обуви.`,`Ответьте продавцу: «Я только смотрю».`]},{day: 15, title: `Ресторан и заказ еды`, title_native: `Restauracja i zamawianie jedzenia`, focus: `Сегодня вы научитесь заказывать еду в ресторане в Кракове. Вы сможете попросить меню, воду, основное блюдо и счёт.`, vocab: [{pl: `restauracja`, ru: `ресторан`, ipa: `[рэстаурацыя]`},{pl: `menu`, ru: `меню`, ipa: `[мэню]`},{pl: `kelner`, ru: `официант`, ipa: `[кэльнэр]`},{pl: `kelnerka`, ru: `официантка`, ipa: `[кэльнэрка]`},{pl: `danie`, ru: `блюдо`, ipa: `[дане]`},{pl: `przystawka`, ru: `закуска`, ipa: `[пшыставка]`},{pl: `deser`, ru: `десерт`, ipa: `[дэсэр]`},{pl: `rachunek`, ru: `счёт`, ipa: `[рахунэк]`},{pl: `woda gazowana`, ru: `газированная вода`, ipa: `[вода газована]`},{pl: `woda niegazowana`, ru: `негазированная вода`, ipa: `[вода негазована]`}], phrases: [{pl: `Poproszę menu.`, ru: `Меню, пожалуйста.`, ipa: `[попроше мэню]`},{pl: `Co pan poleca?`, ru: `Что вы рекомендуете?`, ipa: `[цо пан полэца]`},{pl: `Co pani poleca?`, ru: `Что вы рекомендуете?`, ipa: `[цо пани полэца]`},{pl: `Poproszę danie dnia.`, ru: `Блюдо дня, пожалуйста.`, ipa: `[попроше дане дня]`},{pl: `Poproszę wodę niegazowaną.`, ru: `Негазированную воду, пожалуйста.`, ipa: `[попроше воде негазованом]`},{pl: `Rachunek, proszę.`, ru: `Счёт, пожалуйста.`, ipa: `[рахунэк проше]`}], grammar: `Polecać значит «рекомендовать». К мужчине: Co pan poleca?, к женщине: Co pani poleca? Danie dnia — «блюдо дня», часто хороший вариант в польских ресторанах.`, practice: [`Попросите меню.`,`Спросите официанта-мужчину, что он рекомендует.`,`Закажите негазированную воду.`,`Попросите блюдо дня.`,`Попросите счёт.`]},{day: 16, title: `Диеты и аллергии`, title_native: `Diety i alergie`, focus: `Сегодня вы научитесь объяснять пищевые ограничения в ресторане во Вроцлаве. Это важно, если у вас аллергия или вы не едите определённые продукты.`, vocab: [{pl: `alergia`, ru: `аллергия`, ipa: `[алэргя]`},{pl: `orzechy`, ru: `орехи`, ipa: `[ожэхы]`},{pl: `mleko`, ru: `молоко`, ipa: `[млэко]`},{pl: `gluten`, ru: `глютен`, ipa: `[глютэн]`},{pl: `wegetariański`, ru: `вегетарианский`, ipa: `[вэгэтарианьски]`},{pl: `wegański`, ru: `веганский`, ipa: `[вэганьски]`},{pl: `bez`, ru: `без`, ipa: `[бэз]`},{pl: `ostry`, ru: `острый`, ipa: `[остры]`},{pl: `sól`, ru: `соль`, ipa: `[суль]`},{pl: `cukier`, ru: `сахар`, ipa: `[цукер]`}], phrases: [{pl: `Mam alergię na orzechy.`, ru: `У меня аллергия на орехи.`, ipa: `[мам алэрге на ожэхы]`},{pl: `Czy to jest bez glutenu?`, ru: `Это без глютена?`, ipa: `[чы то ест бэз глютэну]`},{pl: `Czy macie dania wegetariańskie?`, ru: `У вас есть вегетарианские блюда?`, ipa: `[чы маче даня вэгэтарианьске]`},{pl: `Bez mleka, proszę.`, ru: `Без молока, пожалуйста.`, ipa: `[бэз млэка проше]`},{pl: `Nie za ostre, proszę.`, ru: `Не слишком остро, пожалуйста.`, ipa: `[не за острэ проше]`},{pl: `Nie mogę tego jeść.`, ru: `Я не могу это есть.`, ipa: `[не моге тэго ещчь]`}], grammar: `Bez + родительный падеж: bez mleka, bez cukru, bez glutenu. Для аллергии используется конструкция Mam alergię na... Это лучше сказать прямо и заранее, особенно в ресторане.`, practice: [`Скажите, что у вас аллергия на орехи.`,`Попросите блюдо без молока.`,`Спросите, есть ли вегетарианские блюда.`,`Скажите: «Не слишком остро».`,`Объясните, что вы не можете это есть.`]},{day: 17, title: `Погода и планы`, title_native: `Pogoda i plany`, focus: `Сегодня вы научитесь говорить о погоде и простых планах в Гданьске. Это поможет в small talk и при планировании прогулки.`, vocab: [{pl: `pogoda`, ru: `погода`, ipa: `[погода]`},{pl: `słońce`, ru: `солнце`, ipa: `[сўоньцэ]`},{pl: `deszcz`, ru: `дождь`, ipa: `[дэшч]`},{pl: `wiatr`, ru: `ветер`, ipa: `[вятр]`},{pl: `zimno`, ru: `холодно`, ipa: `[жимно]`},{pl: `ciepło`, ru: `тепло`, ipa: `[чепўо]`},{pl: `gorąco`, ru: `жарко`, ipa: `[горонцо]`},{pl: `dzisiaj`, ru: `сегодня`, ipa: `[джищай]`},{pl: `jutro`, ru: `завтра`, ipa: `[ютро]`},{pl: `spacer`, ru: `прогулка`, ipa: `[спацэр]`}], phrases: [{pl: `Jaka jest pogoda?`, ru: `Какая погода?`, ipa: `[яка ест погода]`},{pl: `Dzisiaj jest ciepło.`, ru: `Сегодня тепло.`, ipa: `[джищай ест чепўо]`},{pl: `Pada deszcz.`, ru: `Идёт дождь.`, ipa: `[пада дэщч]`},{pl: `Jutro będzie zimno.`, ru: `Завтра будет холодно.`, ipa: `[ютро бенджэ жимно]`},{pl: `Chcę iść na spacer.`, ru: `Я хочу пойти на прогулку.`, ipa: `[хце ищчь на спацэр]`},{pl: `Nie mam parasola.`, ru: `У меня нет зонта.`, ipa: `[не мам парасола]`}], grammar: `В польском для погоды часто используются безличные выражения: jest zimno, jest ciepło. Pada deszcz буквально «падает дождь». Chcę iść значит «я хочу идти / пойти».`, practice: [`Скажите: «Сегодня тепло».`,`Скажите: «Идёт дождь».`,`Спросите, какая погода.`,`Скажите, что хотите пойти на прогулку.`,`Объясните, что у вас нет зонта.`]},{day: 18, title: `Дни недели и расписание`, title_native: `Dni tygodnia i plan dnia`, focus: `Сегодня вы научитесь говорить о днях недели и расписании. Сцена — вы планируете поездку из Варшавы в Краков.`, vocab: [{pl: `poniedziałek`, ru: `понедельник`, ipa: `[понедзяўэк]`},{pl: `wtorek`, ru: `вторник`, ipa: `[фторэк]`},{pl: `środa`, ru: `среда`, ipa: `[щрода]`},{pl: `czwartek`, ru: `четверг`, ipa: `[чфартэк]`},{pl: `piątek`, ru: `пятница`, ipa: `[пёнтэк]`},{pl: `sobota`, ru: `суббота`, ipa: `[собота]`},{pl: `niedziela`, ru: `воскресенье`, ipa: `[неджеля]`},{pl: `rano`, ru: `утром`, ipa: `[рано]`},{pl: `wieczorem`, ru: `вечером`, ipa: `[вечорэм]`},{pl: `plan`, ru: `план`, ipa: `[плян]`}], phrases: [{pl: `Dzisiaj jest poniedziałek.`, ru: `Сегодня понедельник.`, ipa: `[джищай ест понедзяўэк]`},{pl: `Jutro jest wtorek.`, ru: `Завтра вторник.`, ipa: `[ютро ест фторэк]`},{pl: `W piątek jadę do Krakowa.`, ru: `В пятницу я еду в Краков.`, ipa: `[ф пёнтэк яде до кракова]`},{pl: `Rano mam pociąg.`, ru: `Утром у меня поезд.`, ipa: `[рано мам почёнг]`},{pl: `Wieczorem mam czas.`, ru: `Вечером у меня есть время.`, ipa: `[вечорэм мам час]`},{pl: `Jaki masz plan?`, ru: `Какой у тебя план?`, ipa: `[яки маш плян]`}], grammar: `Для дней недели часто используется w: w piątek, w sobotę, w niedzielę. Rano и wieczorem помогают быстро описать время дня. Mam czas значит «у меня есть время».`, practice: [`Назовите все дни недели по-польски.`,`Скажите, что в пятницу едете в Краков.`,`Скажите: «Утром у меня поезд».`,`Спросите друга о плане.`,`Составьте расписание на один день из трёх фраз.`]},{day: 19, title: `Время на часах`, title_native: `Godzina i czas`, focus: `Сегодня вы научитесь спрашивать и понимать время. Это нужно для поездов, встреч, экскурсий и бронирований.`, vocab: [{pl: `godzina`, ru: `час / время`, ipa: `[годжина]`},{pl: `która`, ru: `который / какая`, ipa: `[ктура]`},{pl: `teraz`, ru: `сейчас`, ipa: `[тэрас]`},{pl: `wpół do`, ru: `половина до`, ipa: `[впув до]`},{pl: `piętnaście`, ru: `пятнадцать`, ipa: `[пентнашче]`},{pl: `minuta`, ru: `минута`, ipa: `[минута]`},{pl: `wcześnie`, ru: `рано`, ipa: `[вчешьне]`},{pl: `późno`, ru: `поздно`, ipa: `[пужно]`},{pl: `spotkanie`, ru: `встреча`, ipa: `[споткане]`},{pl: `rezerwacja`, ru: `бронь`, ipa: `[рэзэрвацыя]`}], phrases: [{pl: `Która godzina?`, ru: `Который час?`, ipa: `[ктура годжина]`},{pl: `Jest trzecia.`, ru: `Три часа.`, ipa: `[ест тшечя]`},{pl: `Jest piętnaście po trzeciej.`, ru: `Пятнадцать минут четвёртого.`, ipa: `[ест пентнашче по тшечей]`},{pl: `Jest wpół do czwartej.`, ru: `Половина четвёртого.`, ipa: `[ест впув до чвартэй]`},{pl: `Mam rezerwację na siódmą.`, ru: `У меня бронь на семь.`, ipa: `[мам рэзэрвацые на щудмом]`},{pl: `Jest za późno.`, ru: `Уже слишком поздно.`, ipa: `[ест за пужно]`}], grammar: `Польское время может звучать непривычно: wpół do czwartej значит «половина до четвёртого», то есть 3:30. Для брони говорят na siódmą — «на семь». В путешествии можно использовать и цифровой вариант: o 15:30.`, practice: [`Спросите: «Который час?»`,`Скажите: «Три часа».`,`Скажите, что у вас бронь на семь.`,`Переведите: «Слишком поздно».`,`Запишите три времени и произнесите их по-польски.`]},{day: 20, title: `Аптека и здоровье`, title_native: `Apteka i zdrowie`, focus: `Сегодня вы научитесь объяснять простые проблемы со здоровьем в аптеке в Познани. Эти фразы помогут купить лекарство или попросить совет.`, vocab: [{pl: `apteka`, ru: `аптека`, ipa: `[аптэка]`},{pl: `lek`, ru: `лекарство`, ipa: `[лек]`},{pl: `ból`, ru: `боль`, ipa: `[буль]`},{pl: `głowa`, ru: `голова`, ipa: `[гўова]`},{pl: `brzuch`, ru: `живот`, ipa: `[бжух]`},{pl: `gardło`, ru: `горло`, ipa: `[гардўо]`},{pl: `kaszel`, ru: `кашель`, ipa: `[кашэль]`},{pl: `gorączka`, ru: `температура`, ipa: `[горончка]`},{pl: `recepta`, ru: `рецепт`, ipa: `[рэцэпта]`},{pl: `pomoc`, ru: `помощь`, ipa: `[помоц]`}], phrases: [{pl: `Boli mnie głowa.`, ru: `У меня болит голова.`, ipa: `[боли мне гўова]`},{pl: `Boli mnie brzuch.`, ru: `У меня болит живот.`, ipa: `[боли мне бжух]`},{pl: `Mam gorączkę.`, ru: `У меня температура.`, ipa: `[мам горончке]`},{pl: `Mam kaszel.`, ru: `У меня кашель.`, ipa: `[мам кашэль]`},{pl: `Czy potrzebuję recepty?`, ru: `Мне нужен рецепт?`, ipa: `[чы потшебуе рэцэпты]`},{pl: `Poproszę coś na ból gardła.`, ru: `Что-нибудь от боли в горле, пожалуйста.`, ipa: `[попроше цось на буль гардўа]`}], grammar: `Для боли используется конструкция Boli mnie... — «у меня болит». Mam gorączkę и mam kaszel буквально «у меня температура / кашель». В аптеке можно сказать Poproszę coś na... — «что-нибудь от...».`, practice: [`Скажите, что у вас болит голова.`,`Скажите, что у вас температура.`,`Попросите что-нибудь от боли в горле.`,`Спросите, нужен ли рецепт.`,`Составьте диалог в аптеке из 6 реплик.`]},{day: 21, title: `Экстренные ситуации`, title_native: `Nagłe sytuacje`, focus: `Сегодня вы научитесь просить срочную помощь. Сцена — вы потеряли телефон или вам нужна полиция в центре города.`, vocab: [{pl: `pomocy`, ru: `помогите`, ipa: `[помоцы]`},{pl: `policja`, ru: `полиция`, ipa: `[полицыя]`},{pl: `ambulans`, ru: `скорая помощь`, ipa: `[амбуланс]`},{pl: `szpital`, ru: `больница`, ipa: `[шпиталь]`},{pl: `telefon`, ru: `телефон`, ipa: `[тэлэфон]`},{pl: `zgubiłem`, ru: `я потерял`, ipa: `[згубивэм]`},{pl: `zgubiłam`, ru: `я потеряла`, ipa: `[згубилам]`},{pl: `kradzież`, ru: `кража`, ipa: `[краджеш]`},{pl: `niebezpiecznie`, ru: `опасно`, ipa: `[небэзпечне]`},{pl: `pilne`, ru: `срочно`, ipa: `[пильнэ]`}], phrases: [{pl: `Pomocy!`, ru: `Помогите!`, ipa: `[помоцы]`},{pl: `Proszę zadzwonić po policję.`, ru: `Позвоните в полицию, пожалуйста.`, ipa: `[проше задзвоничь по полицыю]`},{pl: `Potrzebuję ambulansu.`, ru: `Мне нужна скорая.`, ipa: `[потшебуе амбулансу]`},{pl: `Zgubiłem telefon.`, ru: `Я потерял телефон.`, ipa: `[згубивэм тэлэфон]`},{pl: `Zgubiłam paszport.`, ru: `Я потеряла паспорт.`, ipa: `[згубилам пашпорт]`},{pl: `To pilne.`, ru: `Это срочно.`, ipa: `[то пильнэ]`}], grammar: `Мужчина говорит zgubiłem, женщина — zgubiłam. Potrzebuję + родительный падеж: potrzebuję pomocy, ambulansu, lekarza. В экстренной ситуации говорите коротко и ясно.`, practice: [`Крикните по-польски: «Помогите!»`,`Скажите, что потеряли телефон, выбрав правильную форму.`,`Попросите вызвать полицию.`,`Скажите, что вам нужна скорая.`,`Объясните: «Это срочно».`]},{day: 22, title: `В музее и на экскурсии`, title_native: `W muzeum i na wycieczce`, focus: `Сегодня вы научитесь покупать билеты в музей и задавать вопросы на экскурсии в Кракове. Это поможет при посещении замков, галерей и исторических мест.`, vocab: [{pl: `muzeum`, ru: `музей`, ipa: `[музэум]`},{pl: `bilet`, ru: `билет`, ipa: `[билет]`},{pl: `wystawa`, ru: `выставка`, ipa: `[выстава]`},{pl: `przewodnik`, ru: `гид`, ipa: `[пшэводник]`},{pl: `zamek`, ru: `замок`, ipa: `[замэк]`},{pl: `historia`, ru: `история`, ipa: `[хисторя]`},{pl: `zdjęcie`, ru: `фотография`, ipa: `[здйенче]`},{pl: `zakaz`, ru: `запрет`, ipa: `[заказ]`},{pl: `wejście`, ru: `вход`, ipa: `[вэйщче]`},{pl: `wyjście`, ru: `выход`, ipa: `[выйщче]`}], phrases: [{pl: `Poproszę jeden bilet.`, ru: `Один билет, пожалуйста.`, ipa: `[попроше еден билет]`},{pl: `Czy można robić zdjęcia?`, ru: `Можно фотографировать?`, ipa: `[чы можна робичь здйенчя]`},{pl: `Gdzie jest wejście?`, ru: `Где вход?`, ipa: `[гджэ ест вэйщче]`},{pl: `Gdzie jest wyjście?`, ru: `Где выход?`, ipa: `[гджэ ест выйщче]`},{pl: `Czy jest przewodnik po rosyjsku?`, ru: `Есть гид на русском?`, ipa: `[чы ест пшэводник по росыйску]`},{pl: `O której zaczyna się wycieczka?`, ru: `Во сколько начинается экскурсия?`, ipa: `[о ктурэй зачына ще вычечка]`}], grammar: `Czy można...? — универсальный способ спросить разрешение: Czy można robić zdjęcia? В польских музеях могут быть зоны с zakaz fotografowania — запретом фотографировать. Wycieczka значит экскурсия или поездка.`, practice: [`Купите один билет в музей.`,`Спросите, можно ли фотографировать.`,`Спросите, где вход и выход.`,`Узнайте, есть ли гид на русском.`,`Спросите, во сколько начинается экскурсия.`]},{day: 23, title: `Общение с местными`, title_native: `Rozmowa z mieszkańcami`, focus: `Сегодня вы научитесь поддерживать простой разговор с местными жителями. Сцена — вы сидите в кафе в Люблине и начинаете small talk.`, vocab: [{pl: `mieszkaniec`, ru: `житель`, ipa: `[мешканец]`},{pl: `miasto`, ru: `город`, ipa: `[място]`},{pl: `ładny`, ru: `красивый`, ipa: `[ўадны]`},{pl: `ciekawy`, ru: `интересный`, ipa: `[чекавы]`},{pl: `spokojny`, ru: `спокойный`, ipa: `[спокойны]`},{pl: `głośny`, ru: `шумный`, ipa: `[гўошны]`},{pl: `podobać się`, ru: `нравиться`, ipa: `[подобачь ще]`},{pl: `pierwszy raz`, ru: `первый раз`, ipa: `[пьерфшы раз]`},{pl: `często`, ru: `часто`, ipa: `[чэнсто]`},{pl: `czasem`, ru: `иногда`, ipa: `[часэм]`}], phrases: [{pl: `To piękne miasto.`, ru: `Это красивый город.`, ipa: `[то пьенкнэ място]`},{pl: `Jestem tu pierwszy raz.`, ru: `Я здесь в первый раз.`, ipa: `[естэм ту пьерфшы раз]`},{pl: `Bardzo mi się podoba.`, ru: `Мне очень нравится.`, ipa: `[бардзо ми ще подоба]`},{pl: `Czy często pan tu przychodzi?`, ru: `Вы часто сюда приходите?`, ipa: `[чы чэнсто пан ту пшиходжи]`},{pl: `Czy często pani tu przychodzi?`, ru: `Вы часто сюда приходите?`, ipa: `[чы чэнсто пани ту пшиходжи]`},{pl: `Lubię spokojne miejsca.`, ru: `Я люблю спокойные места.`, ipa: `[лубе спокойнэ мейсца]`}], grammar: `Tu значит «здесь / сюда» в разговорной речи. Bardzo mi się podoba — удобная фраза, чтобы сказать, что вам нравится место, город или еда. К незнакомым взрослым используйте pan или pani.`, practice: [`Скажите, что город красивый.`,`Скажите, что вы здесь впервые.`,`Скажите: «Мне очень нравится».`,`Спросите женщину, часто ли она сюда приходит.`,`Расскажите, какие места вы любите.`]},{day: 24, title: `Приглашения и встречи`, title_native: `Zaproszenia i spotkania`, focus: `Сегодня вы научитесь договариваться о встрече. Сцена — вы познакомились с человеком в Кракове и хотите встретиться вечером.`, vocab: [{pl: `spotkanie`, ru: `встреча`, ipa: `[споткане]`},{pl: `czas`, ru: `время`, ipa: `[час]`},{pl: `dzisiaj`, ru: `сегодня`, ipa: `[джищай]`},{pl: `jutro`, ru: `завтра`, ipa: `[ютро]`},{pl: `wieczór`, ru: `вечер`, ipa: `[вечур]`},{pl: `kawiarnia`, ru: `кафе`, ipa: `[кавярня]`},{pl: `restauracja`, ru: `ресторан`, ipa: `[рэстаурацыя]`},{pl: `może`, ru: `может быть`, ipa: `[можэ]`},{pl: `pasuje`, ru: `подходит`, ipa: `[пасуе]`},{pl: `niestety`, ru: `к сожалению`, ipa: `[нестэты]`}], phrases: [{pl: `Masz czas dzisiaj?`, ru: `У тебя есть время сегодня?`, ipa: `[маш час джищай]`},{pl: `Może kawa?`, ru: `Может, кофе?`, ipa: `[можэ кава]`},{pl: `O której ci pasuje?`, ru: `Во сколько тебе удобно?`, ipa: `[о ктурэй чи пасуе]`},{pl: `Pasuje mi o szóstej.`, ru: `Мне подходит в шесть.`, ipa: `[пасуе ми о шустэй]`},{pl: `Niestety nie mogę.`, ru: `К сожалению, я не могу.`, ipa: `[нестэты не моге]`},{pl: `Do zobaczenia.`, ru: `До встречи.`, ipa: `[до zobачэня]`}], grammar: `В неформальной ситуации можно говорить masz и ci. С незнакомыми людьми лучше: Czy ma pan czas? или Czy ma pani czas? Pasuje mi значит «мне подходит» и очень часто используется для договорённостей.`, practice: [`Спросите друга, есть ли у него время сегодня.`,`Предложите кофе.`,`Спросите, во сколько удобно.`,`Скажите, что вам подходит в шесть.`,`Вежливо откажитесь.`]},{day: 25, title: `Телефон и интернет`, title_native: `Telefon i internet`, focus: `Сегодня вы научитесь говорить о SIM-карте, интернете и Wi-Fi. Сцена — салон связи в Варшаве.`, vocab: [{pl: `telefon`, ru: `телефон`, ipa: `[тэлэфон]`},{pl: `internet`, ru: `интернет`, ipa: `[интэрнэт]`},{pl: `Wi-Fi`, ru: `вай-фай`, ipa: `[вай-фай]`},{pl: `karta SIM`, ru: `SIM-карта`, ipa: `[карта сим]`},{pl: `hasło`, ru: `пароль`, ipa: `[хасўо]`},{pl: `sieć`, ru: `сеть`, ipa: `[щечь]`},{pl: `działa`, ru: `работает`, ipa: `[джяўа]`},{pl: `nie działa`, ru: `не работает`, ipa: `[не джяўа]`},{pl: `ładowarka`, ru: `зарядка`, ipa: `[ўадоварка]`},{pl: `bateria`, ru: `батарея`, ipa: `[батэрыя]`}], phrases: [{pl: `Czy jest Wi-Fi?`, ru: `Есть Wi-Fi?`, ipa: `[чы ест вай-фай]`},{pl: `Jakie jest hasło?`, ru: `Какой пароль?`, ipa: `[яке ест хасўо]`},{pl: `Internet nie działa.`, ru: `Интернет не работает.`, ipa: `[интэрнэт не джяўа]`},{pl: `Potrzebuję karty SIM.`, ru: `Мне нужна SIM-карта.`, ipa: `[потшебуе карты сим]`},{pl: `Czy macie ładowarkę?`, ru: `У вас есть зарядка?`, ipa: `[чы маче ўадоварке]`},{pl: `Mój telefon się rozładował.`, ru: `Мой телефон разрядился.`, ipa: `[муй тэлэфон ще розўадовав]`}], grammar: `Działa значит «работает» для техники, интернета и приложений. Hasło — пароль, его часто спрашивают в кафе и отелях. Potrzebuję karty SIM — полезная фраза в салоне связи.`, practice: [`Спросите, есть ли Wi-Fi.`,`Спросите пароль.`,`Скажите, что интернет не работает.`,`Попросите SIM-карту.`,`Объясните, что телефон разрядился.`]},{day: 26, title: `На почте и отправка вещей`, title_native: `Na poczcie i wysyłanie rzeczy`, focus: `Сегодня вы научитесь отправлять открытку или посылку из Польши. Сцена — почтовое отделение в Гданьске.`, vocab: [{pl: `poczta`, ru: `почта`, ipa: `[почта]`},{pl: `list`, ru: `письмо`, ipa: `[лист]`},{pl: `kartka`, ru: `открытка`, ipa: `[картка]`},{pl: `paczka`, ru: `посылка`, ipa: `[пачка]`},{pl: `znaczek`, ru: `марка`, ipa: `[значэк]`},{pl: `adres`, ru: `адрес`, ipa: `[адрэс]`},{pl: `wysłać`, ru: `отправить`, ipa: `[выслать]`},{pl: `odbiór`, ru: `получение`, ipa: `[одбюр]`},{pl: `priorytet`, ru: `приоритет`, ipa: `[приорытэт]`},{pl: `zagranica`, ru: `заграница`, ipa: `[заграница]`}], phrases: [{pl: `Chcę wysłać kartkę.`, ru: `Я хочу отправить открытку.`, ipa: `[хце выслать картке]`},{pl: `Poproszę znaczek do Rosji.`, ru: `Марку в Россию, пожалуйста.`, ipa: `[попроше значэк до росъи]`},{pl: `Ile kosztuje wysyłka?`, ru: `Сколько стоит отправка?`, ipa: `[иле коштуе высылка]`},{pl: `Czy to priorytet?`, ru: `Это приоритетная отправка?`, ipa: `[чы то приорытэт]`},{pl: `Gdzie mam napisać adres?`, ru: `Где мне написать адрес?`, ipa: `[гджэ мам написачь адрэс]`},{pl: `Chcę wysłać paczkę.`, ru: `Я хочу отправить посылку.`, ipa: `[хце выслать пачке]`}], grammar: `Chcę wysłać — «я хочу отправить». Do Rosji, do Polski, do Niemiec используются для направления. На почте лучше говорить короткими фразами и показывать адрес.`, practice: [`Скажите, что хотите отправить открытку.`,`Попросите марку в Россию.`,`Спросите стоимость отправки.`,`Спросите, где написать адрес.`,`Скажите, что хотите отправить посылку.`]},{day: 27, title: `Банк и банкомат`, title_native: `Bank i bankomat`, focus: `Сегодня вы научитесь снимать деньги и решать простые проблемы с картой. Сцена — банкомат и отделение банка во Вроцлаве.`, vocab: [{pl: `bank`, ru: `банк`, ipa: `[банк]`},{pl: `bankomat`, ru: `банкомат`, ipa: `[банкомат]`},{pl: `karta`, ru: `карта`, ipa: `[карта]`},{pl: `gotówka`, ru: `наличные`, ipa: `[готувка]`},{pl: `pieniądze`, ru: `деньги`, ipa: `[пенёндзэ]`},{pl: `konto`, ru: `счёт`, ipa: `[конто]`},{pl: `wypłata`, ru: `снятие денег`, ipa: `[выпўата]`},{pl: `wpłata`, ru: `внесение денег`, ipa: `[впўата]`},{pl: `PIN`, ru: `ПИН-код`, ipa: `[пин]`},{pl: `problem`, ru: `проблема`, ipa: `[проблэм]`}], phrases: [{pl: `Gdzie jest bankomat?`, ru: `Где банкомат?`, ipa: `[гджэ ест банкомат]`},{pl: `Chcę wypłacić pieniądze.`, ru: `Я хочу снять деньги.`, ipa: `[хце выпўачичь пенёндзэ]`},{pl: `Karta nie działa.`, ru: `Карта не работает.`, ipa: `[карта не джяўа]`},{pl: `Zapomniałem PIN-u.`, ru: `Я забыл ПИН-код.`, ipa: `[запомнявэм пину]`},{pl: `Zapomniałam PIN-u.`, ru: `Я забыла ПИН-код.`, ipa: `[запомнялам пину]`},{pl: `Czy jest prowizja?`, ru: `Есть комиссия?`, ipa: `[чы ест провизья]`}], grammar: `Chcę wypłacić pieniądze значит «я хочу снять деньги». Мужчина говорит zapomniałem, женщина — zapomniałam. Prowizja — комиссия, важное слово при снятии денег за границей.`, practice: [`Спросите, где банкомат.`,`Скажите, что хотите снять деньги.`,`Объясните, что карта не работает.`,`Скажите, что забыли ПИН-код, выбрав правильную форму.`,`Спросите, есть ли комиссия.`]},{day: 28, title: `Проблемы в поездке`, title_native: `Problemy w podróży`, focus: `Сегодня вы научитесь описывать задержки, потерянные вещи и ошибки в брони. Сцена — вокзал или отель в Варшаве.`, vocab: [{pl: `problem`, ru: `проблема`, ipa: `[проблэм]`},{pl: `opóźnienie`, ru: `задержка`, ipa: `[опужнене]`},{pl: `zgubiony`, ru: `потерянный`, ipa: `[згубёны]`},{pl: `błąd`, ru: `ошибка`, ipa: `[бвонд]`},{pl: `rezerwacja`, ru: `бронь`, ipa: `[рэзэрвацыя]`},{pl: `walizka`, ru: `чемодан`, ipa: `[валиска]`},{pl: `plecak`, ru: `рюкзак`, ipa: `[плэцак]`},{pl: `dokument`, ru: `документ`, ipa: `[докумэнт]`},{pl: `pomóc`, ru: `помочь`, ipa: `[помуц]`},{pl: `sprawdzić`, ru: `проверить`, ipa: `[справджичь]`}], phrases: [{pl: `Mam problem.`, ru: `У меня проблема.`, ipa: `[мам проблэм]`},{pl: `Moja rezerwacja zniknęła.`, ru: `Моя бронь исчезла.`, ipa: `[моя рэзэрвацыя зникнэўа]`},{pl: `Zgubiłem walizkę.`, ru: `Я потерял чемодан.`, ipa: `[згубивэм валиске]`},{pl: `Zgubiłam dokumenty.`, ru: `Я потеряла документы.`, ipa: `[згубилам докумэнты]`},{pl: `Czy może pan sprawdzić?`, ru: `Вы можете проверить?`, ipa: `[чы можэ пан справджичь]`},{pl: `Czy może pani mi pomóc?`, ru: `Вы можете мне помочь?`, ipa: `[чы можэ пани ми помуц]`}], grammar: `Może pan...? и może pani...? — вежливый способ попросить человека что-то сделать. Zgubiłem и zgubiłam снова зависят от пола говорящего. В стрессовой ситуации начните с Mam problem.`, practice: [`Скажите: «У меня проблема».`,`Объясните, что потеряли чемодан.`,`Попросите мужчину проверить бронь.`,`Попросите женщину помочь.`,`Составьте диалог о потерянных документах.`]},{day: 29, title: `Мнения и впечатления`, title_native: `Opinie i wrażenia`, focus: `Сегодня вы научитесь делиться впечатлениями о поездке. Сцена — разговор с местным жителем или другим туристом в Кракове.`, vocab: [{pl: `podróż`, ru: `путешествие`, ipa: `[подруж]`},{pl: `wrażenie`, ru: `впечатление`, ipa: `[вражэне]`},{pl: `piękny`, ru: `красивый`, ipa: `[пьенкны]`},{pl: `ciekawy`, ru: `интересный`, ipa: `[чекавы]`},{pl: `trudny`, ru: `трудный`, ipa: `[трудны]`},{pl: `łatwy`, ru: `лёгкий`, ipa: `[ўатвы]`},{pl: `drogi`, ru: `дорогой`, ipa: `[дроги]`},{pl: `tani`, ru: `дешёвый`, ipa: `[тани]`},{pl: `miły`, ru: `приятный`, ipa: `[милы]`},{pl: `super`, ru: `супер`, ipa: `[супэр]`}], phrases: [{pl: `Polska jest piękna.`, ru: `Польша красивая.`, ipa: `[польска ест пьенкна]`},{pl: `To było ciekawe.`, ru: `Это было интересно.`, ipa: `[то было чекавэ]`},{pl: `Jedzenie było smaczne.`, ru: `Еда была вкусной.`, ipa: `[едзэне было смачнэ]`},{pl: `Ludzie są mili.`, ru: `Люди приятные.`, ipa: `[лудже сом мили]`},{pl: `To było trochę trudne.`, ru: `Это было немного трудно.`, ipa: `[то было трохе труднэ]`},{pl: `Bardzo mi się podobało.`, ru: `Мне очень понравилось.`, ipa: `[бардзо ми ще подобаўо]`}], grammar: `Było значит «было» и удобно для впечатлений: było ciekawe, było trudne, było smaczne. Bardzo mi się podobało — универсальная фраза после экскурсии, ужина или поездки. Прилагательные меняются по роду, но готовые фразы помогут начать говорить.`, practice: [`Скажите, что Польша красивая.`,`Скажите, что еда была вкусной.`,`Скажите, что люди приятные.`,`Расскажите, что было немного трудно.`,`Опишите свою поездку тремя фразами.`]},{day: 30, title: `Повторение и уверенное путешествие`, title_native: `Powtórka i pewna podróż`, focus: `Сегодня вы соберёте всё вместе: приветствие, просьбы, транспорт, еду, отель и проблемы. Сцена — один полный день путешественника в Варшаве.`, vocab: [{pl: `podróżnik`, ru: `путешественник`, ipa: `[подружник]`},{pl: `plan`, ru: `план`, ipa: `[плян]`},{pl: `centrum`, ru: `центр`, ipa: `[цэнтрум]`},{pl: `jedzenie`, ru: `еда`, ipa: `[едзэне]`},{pl: `bilet`, ru: `билет`, ipa: `[билет]`},{pl: `hotel`, ru: `отель`, ipa: `[хотэль]`},{pl: `pomoc`, ru: `помощь`, ipa: `[помоц]`},{pl: `rachunek`, ru: `счёт`, ipa: `[рахунэк]`},{pl: `adres`, ru: `адрес`, ipa: `[адрэс]`},{pl: `dziękuję`, ru: `спасибо`, ipa: `[дженкуе]`}], phrases: [{pl: `Dzień dobry, mam pytanie.`, ru: `Добрый день, у меня вопрос.`, ipa: `[джень добры, мам пытане]`},{pl: `Czy może mi pan pomóc?`, ru: `Вы можете мне помочь?`, ipa: `[чы можэ ми пан помуц]`},{pl: `Czy może mi pani pomóc?`, ru: `Вы можете мне помочь?`, ipa: `[чы можэ ми пани помуц]`},{pl: `Poproszę bilet do centrum.`, ru: `Билет до центра, пожалуйста.`, ipa: `[попроше билет до цэнтрум]`},{pl: `Mam rezerwację w hotelu.`, ru: `У меня бронь в отеле.`, ipa: `[мам рэзэрвацые в хотэлю]`},{pl: `Dziękuję, do widzenia.`, ru: `Спасибо, до свидания.`, ipa: `[дженкуе, до видзэня]`}], grammar: `В путешествии важнее не идеальная грамматика, а понятные и вежливые фразы. Начинайте с Dzień dobry, используйте proszę и dziękuję, а при проблемах говорите Mam problem или Czy może mi pan/pani pomóc? Эти конструкции покроют большинство реальных ситуаций.`, practice: [`Составьте диалог на ресепшене отеля.`,`Составьте заказ в кафе из трёх позиций.`,`Спросите дорогу до центра.`,`Объясните проблему с билетом.`,`Расскажите о своём дне в Польше пятью польскими фразами.`]}];

var CONVERSATIONS_RU_PL = [{id: 1, title: `Заказ в кафе`, scene: `Вы заходите в небольшое кафе в Кракове утром. Бариста приветствует вас и спрашивает, что вы хотите заказать.`, lines: [{who: `them`, pl: `Dzień dobry, co podać?`, ru: `Добрый день, что вам подать?`},{who: `you`, pl: `Dzień dobry, poproszę kawę.`, ru: `Добрый день, кофе, пожалуйста.`},{who: `them`, pl: `Małą czy dużą?`, ru: `Маленькую или большую?`},{who: `you`, pl: `Dużą, proszę.`, ru: `Большую, пожалуйста.`},{who: `them`, pl: `Z mlekiem czy bez mleka?`, ru: `С молоком или без молока?`},{who: `you`, pl: `Z mlekiem, ale bez cukru.`, ru: `С молоком, но без сахара.`},{who: `them`, pl: `Czy coś jeszcze?`, ru: `Что-нибудь ещё?`},{who: `you`, pl: `Tak, poproszę ciasto.`, ru: `Да, пирожное, пожалуйста.`},{who: `them`, pl: `Na miejscu czy na wynos?`, ru: `Здесь или с собой?`},{who: `you`, pl: `Na miejscu, proszę.`, ru: `Здесь, пожалуйста.`},{who: `them`, pl: `Razem dwadzieścia złotych.`, ru: `Вместе двадцать злотых.`},{who: `you`, pl: `Proszę, dziękuję.`, ru: `Пожалуйста, спасибо.`}]},{id: 2, title: `Заселение в отель`, scene: `Вы приезжаете в отель в Гданьске после долгой дороги. На ресепшене нужно подтвердить бронь и узнать про завтрак.`, lines: [{who: `them`, pl: `Dzień dobry, witamy w hotelu.`, ru: `Добрый день, добро пожаловать в отель.`},{who: `you`, pl: `Dzień dobry, mam rezerwację.`, ru: `Добрый день, у меня бронь.`},{who: `them`, pl: `Na jakie nazwisko?`, ru: `На какую фамилию?`},{who: `you`, pl: `Na nazwisko Iwanow.`, ru: `На фамилию Иванов.`},{who: `them`, pl: `Poproszę paszport.`, ru: `Паспорт, пожалуйста.`},{who: `you`, pl: `Oto mój paszport.`, ru: `Вот мой паспорт.`},{who: `them`, pl: `Pokój jest na trzecim piętrze.`, ru: `Номер на третьем этаже.`},{who: `you`, pl: `Czy śniadanie jest w cenie?`, ru: `Завтрак включён в цену?`},{who: `them`, pl: `Tak, od siódmej do dziesiątej.`, ru: `Да, с семи до десяти.`},{who: `you`, pl: `Gdzie jest winda?`, ru: `Где лифт?`},{who: `them`, pl: `Winda jest po lewej stronie.`, ru: `Лифт с левой стороны.`},{who: `you`, pl: `Dziękuję bardzo.`, ru: `Большое спасибо.`}]},{id: 3, title: `Как спросить дорогу`, scene: `Вы находитесь в центре Варшавы и ищете Старый город. Вы останавливаете прохожего и просите помочь.`, lines: [{who: `you`, pl: `Przepraszam, mam pytanie.`, ru: `Извините, у меня вопрос.`},{who: `them`, pl: `Tak, proszę.`, ru: `Да, пожалуйста.`},{who: `you`, pl: `Gdzie jest Stare Miasto?`, ru: `Где Старый город?`},{who: `them`, pl: `Proszę iść prosto.`, ru: `Идите прямо, пожалуйста.`},{who: `you`, pl: `Prosto, dobrze.`, ru: `Прямо, хорошо.`},{who: `them`, pl: `Potem w prawo przy placu.`, ru: `Потом направо у площади.`},{who: `you`, pl: `Czy to daleko?`, ru: `Это далеко?`},{who: `them`, pl: `Nie, to bardzo blisko.`, ru: `Нет, это очень близко.`},{who: `you`, pl: `Ile minut pieszo?`, ru: `Сколько минут пешком?`},{who: `them`, pl: `Około dziesięciu minut.`, ru: `Около десяти минут.`},{who: `you`, pl: `Dziękuję za pomoc.`, ru: `Спасибо за помощь.`},{who: `them`, pl: `Nie ma za co.`, ru: `Не за что.`}]},{id: 4, title: `Ужин в ресторане`, scene: `Вы приходите в ресторан во Вроцлаве вечером. Официант помогает выбрать блюдо и приносит счёт.`, lines: [{who: `them`, pl: `Dobry wieczór, czy mają państwo rezerwację?`, ru: `Добрый вечер, у вас есть бронь?`},{who: `you`, pl: `Nie, stolik dla jednej osoby, proszę.`, ru: `Нет, столик на одного человека, пожалуйста.`},{who: `them`, pl: `Oczywiście, proszę tutaj.`, ru: `Конечно, пожалуйста, сюда.`},{who: `you`, pl: `Poproszę menu.`, ru: `Меню, пожалуйста.`},{who: `them`, pl: `Proszę bardzo.`, ru: `Пожалуйста.`},{who: `you`, pl: `Co pani poleca?`, ru: `Что вы рекомендуете?`},{who: `them`, pl: `Polecam pierogi i zupę dnia.`, ru: `Рекомендую пироги и суп дня.`},{who: `you`, pl: `Poproszę pierogi i wodę niegazowaną.`, ru: `Пироги и негазированную воду, пожалуйста.`},{who: `them`, pl: `Czy coś na deser?`, ru: `Что-нибудь на десерт?`},{who: `you`, pl: `Nie, dziękuję, poproszę rachunek.`, ru: `Нет, спасибо, счёт, пожалуйста.`},{who: `them`, pl: `Oczywiście, już przynoszę.`, ru: `Конечно, сейчас принесу.`},{who: `you`, pl: `Dziękuję, było bardzo smaczne.`, ru: `Спасибо, было очень вкусно.`}]},{id: 5, title: `Покупка билета на транспорт`, scene: `Вы на станции метро в Варшаве и хотите купить билет до центра. Сотрудник помогает выбрать правильный билет.`, lines: [{who: `them`, pl: `Dzień dobry, w czym mogę pomóc?`, ru: `Добрый день, чем могу помочь?`},{who: `you`, pl: `Poproszę bilet do centrum.`, ru: `Билет до центра, пожалуйста.`},{who: `them`, pl: `Normalny czy ulgowy?`, ru: `Обычный или льготный?`},{who: `you`, pl: `Normalny, proszę.`, ru: `Обычный, пожалуйста.`},{who: `them`, pl: `Jeden bilet?`, ru: `Один билет?`},{who: `you`, pl: `Tak, jeden bilet.`, ru: `Да, один билет.`},{who: `them`, pl: `To kosztuje cztery złote.`, ru: `Это стоит четыре злотых.`},{who: `you`, pl: `Czy mogę zapłacić kartą?`, ru: `Можно оплатить картой?`},{who: `them`, pl: `Tak, oczywiście.`, ru: `Да, конечно.`},{who: `you`, pl: `Czy muszę skasować bilet?`, ru: `Нужно активировать билет?`},{who: `them`, pl: `Tak, przed wejściem do metra.`, ru: `Да, перед входом в метро.`},{who: `you`, pl: `Dziękuję za informację.`, ru: `Спасибо за информацию.`}]},{id: 6, title: `Покупки в магазине`, scene: `Вы заходите в небольшой продуктовый магазин в Лодзи. Вам нужны вода, хлеб и пакет.`, lines: [{who: `them`, pl: `Dzień dobry.`, ru: `Добрый день.`},{who: `you`, pl: `Dzień dobry, poproszę wodę i chleb.`, ru: `Добрый день, воду и хлеб, пожалуйста.`},{who: `them`, pl: `Wodę gazowaną czy niegazowaną?`, ru: `Воду газированную или негазированную?`},{who: `you`, pl: `Niegazowaną, proszę.`, ru: `Негазированную, пожалуйста.`},{who: `them`, pl: `Coś jeszcze?`, ru: `Что-нибудь ещё?`},{who: `you`, pl: `Tak, poproszę dwa jabłka.`, ru: `Да, два яблока, пожалуйста.`},{who: `them`, pl: `Czy potrzebna torba?`, ru: `Нужен пакет?`},{who: `you`, pl: `Tak, poproszę torbę.`, ru: `Да, пакет, пожалуйста.`},{who: `them`, pl: `Razem dwanaście złotych.`, ru: `Вместе двенадцать злотых.`},{who: `you`, pl: `Proszę bardzo.`, ru: `Пожалуйста.`},{who: `them`, pl: `Paragon?`, ru: `Чек?`},{who: `you`, pl: `Tak, poproszę paragon.`, ru: `Да, чек, пожалуйста.`}]},{id: 7, title: `В аптеке`, scene: `У вас болит горло во время поездки в Познань. Вы заходите в аптеку и просите что-нибудь без рецепта.`, lines: [{who: `them`, pl: `Dzień dobry, słucham.`, ru: `Добрый день, слушаю вас.`},{who: `you`, pl: `Dzień dobry, boli mnie gardło.`, ru: `Добрый день, у меня болит горло.`},{who: `them`, pl: `Czy ma pan gorączkę?`, ru: `У вас есть температура?`},{who: `you`, pl: `Nie, nie mam gorączki.`, ru: `Нет, температуры нет.`},{who: `them`, pl: `Czy ma pan kaszel?`, ru: `У вас есть кашель?`},{who: `you`, pl: `Trochę, ale nie bardzo.`, ru: `Немного, но не сильно.`},{who: `them`, pl: `Mogę polecić tabletki na gardło.`, ru: `Могу порекомендовать таблетки от горла.`},{who: `you`, pl: `Czy potrzebuję recepty?`, ru: `Мне нужен рецепт?`},{who: `them`, pl: `Nie, to jest bez recepty.`, ru: `Нет, это без рецепта.`},{who: `you`, pl: `Dobrze, poproszę.`, ru: `Хорошо, пожалуйста.`},{who: `them`, pl: `Proszę brać trzy razy dziennie.`, ru: `Принимайте три раза в день.`},{who: `you`, pl: `Dziękuję za pomoc.`, ru: `Спасибо за помощь.`}]},{id: 8, title: `Разговор с местным жителем`, scene: `Вы сидите на скамейке у реки в Гданьске. Местный житель начинает дружелюбный разговор о городе и вашей поездке.`, lines: [{who: `you`, pl: `Przepraszam, czy to miejsce jest wolne?`, ru: `Извините, это место свободно?`},{who: `them`, pl: `Tak, proszę siadać.`, ru: `Да, садитесь, пожалуйста.`},{who: `you`, pl: `Dziękuję, to piękne miasto.`, ru: `Спасибо, это красивый город.`},{who: `them`, pl: `To prawda, Gdańsk jest wyjątkowy.`, ru: `Это правда, Гданьск особенный.`},{who: `you`, pl: `Jestem tu pierwszy raz.`, ru: `Я здесь впервые.`},{who: `them`, pl: `I jak się panu podoba?`, ru: `И как вам нравится?`},{who: `you`, pl: `Bardzo mi się podoba.`, ru: `Мне очень нравится.`},{who: `them`, pl: `Czy próbował pan pierogów?`, ru: `Вы пробовали пироги?`},{who: `you`, pl: `Tak, były bardzo smaczne.`, ru: `Да, они были очень вкусные.`},{who: `them`, pl: `Warto też zobaczyć plażę w Sopocie.`, ru: `Стоит также увидеть пляж в Сопоте.`},{who: `you`, pl: `Dziękuję za radę.`, ru: `Спасибо за совет.`},{who: `them`, pl: `Miłego pobytu w Polsce.`, ru: `Приятного пребывания в Польше.`}]}];